import React from "react";
import { useScrollReveal, useParallax } from "./useScrollAnimation";
import "./HowItWorks.css";

const ss = (v, a, b) => Math.max(0, Math.min(1, (v - a) / (b - a)));

function useElP() {
  const ref = React.useRef(null);
  const [p, setP] = React.useState(0);

  React.useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const fn = () => {
      const { top, height } = el.getBoundingClientRect();
      setP(Math.max(0, Math.min(1, (window.innerHeight - top) / (window.innerHeight + height))));
    };

    fn();
    window.addEventListener("scroll", fn, { passive: true });
    return () => window.removeEventListener("scroll", fn);
  }, []);

  return [ref, p];
}

function FlowSection({ go }) {
  const [ref, p] = useElP();
  const nodes = [
    { icon: "📄", label: "Your PDF", sub: "Any research paper" },
    { arrow: true },
    { icon: "🌐", label: "IPFS", sub: "SHA-256 → CID" },
    { arrow: true },
    { icon: "⛓", label: "Blockchain", sub: "CID + Wallet + Timestamp" },
    { arrow: true },
    { icon: "✅", label: "Proof", sub: "Public · Permanent · Verified" },
  ];

  const titleProg = ss(p, 0.04, 0.24);

  return (
    <section className="hiw-flow" ref={ref}>
      <div
        className="hiw-flow__bleed"
        style={{ transform: `translate(-50%,-50%) translateY(${(p - 0.5) * -55}px)` }}
      >
        FLOW
      </div>

      <div className="hiw-flow__inner">
        <div style={{ opacity: titleProg, transform: `translateY(${(1 - titleProg) * 40}px)` }}>
          <div className="eyebrow">The Complete Flow</div>
          <h2 className="hiw-flow__h2">End-to-end in one view.</h2>
        </div>

        <div className="hiw-flow__row">
          {nodes.map((item, i) => {
            const np = ss(p, 0.18 + i * 0.045, 0.44 + i * 0.045);
            return item.arrow ? (
              <div
                className="hiw-flow__arr"
                key={i}
                style={{ opacity: np, transform: `translateX(${(1 - np) * -12}px)` }}
              >
                →
              </div>
            ) : (
              <div
                className="hiw-flow__node"
                key={i}
                style={{
                  opacity: np,
                  transform: `translateY(${(1 - np) * 36}px) scale(${0.88 + np * 0.12})`,
                }}
              >
                <div className="hiw-flow__node-icon">{item.icon}</div>
                <div className="hiw-flow__node-label">{item.label}</div>
                <div className="hiw-flow__node-sub">{item.sub}</div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

function StepsSection() {
  const [ref, p] = useElP();

  const steps = [
    {
      title: "Upload",
      desc: "Drop your PDF and send it to IPFS.",
    },
    {
      title: "Generate CID",
      desc: "The file content becomes a unique immutable identifier.",
    },
    {
      title: "Submit On-Chain",
      desc: "Record the CID on the smart contract with your wallet.",
    },
    {
      title: "Verify",
      desc: "Anyone can check authorship and timestamp publicly.",
    },
  ];

  return (
    <section className="hiw-steps" ref={ref}>
      <div className="hiw-steps__inner">
        <div style={{ opacity: ss(p, 0.06, 0.22), transform: `translateY(${(1 - ss(p, 0.06, 0.22)) * 36}px)` }}>
          <div className="eyebrow">How It Works</div>
          <h2 className="hiw-steps__h2">Four steps. One proof.</h2>
        </div>

        <div className="hiw-steps__grid">
          {steps.map((step, i) => {
            const sp = ss(p, 0.12 + i * 0.07, 0.38 + i * 0.07);
            return (
              <div
                className="hiw-step"
                key={step.title}
                style={{
                  opacity: sp,
                  transform: `translateY(${(1 - sp) * 24}px)`,
                }}
              >
                <div className="hiw-step__num">0{i + 1}</div>
                <h3 className="hiw-step__title">{step.title}</h3>
                <p className="hiw-step__desc">{step.desc}</p>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

export function HowItWorks({ navigate }) {
  useScrollReveal(0.12);
  const [bgRef, bgOff] = useParallax(0.3);
  const [bleedRef, blOff] = useParallax(-0.08);
  const [textRef, textOff] = useParallax(0.12);

  const go = (p) => {
    navigate(p);
    window.scrollTo({ top: 0 });
  };

  return (
    <div className="hiw page-enter">
      <section className="hiw-hero">
        <div
          ref={bgRef}
          className="hiw-hero__bg"
          style={{ transform: `translateY(${bgOff}px) scale(1.15)` }}
        />
        <div className="hiw-hero__ov" />
        <div className="hiw-hero__grid" />
        <div
          ref={bleedRef}
          className="hiw-hero__bleed"
          style={{ transform: `translate(-50%,-50%) translateY(${blOff}px)` }}
        >
          HOW IT WORKS
        </div>

        <div ref={textRef} className="hiw-hero__content" style={{ transform: `translateY(${textOff}px)` }}>
          <div className="eyebrow" data-reveal="fade">
            Under the Hood
          </div>
          <h1 className="hiw-hero__h1" data-reveal="up" data-reveal-delay="80">
            From PDF to permanent
            <br />
            <em className="gold-text">proof of precedence.</em>
          </h1>
          <p className="hiw-hero__sub" data-reveal="fade" data-reveal-delay="180">
            Upload the paper, store its CID, and anchor it on-chain so authorship and timestamp are verifiable forever.
          </p>
        </div>
      </section>

      <FlowSection go={go} />
      <StepsSection />

      <section className="hiw-cta">
        <div className="hiw-cta__inner" data-reveal="up">
          <h2 className="hiw-cta__h2">Ready to try it yourself?</h2>
          <div className="hiw-cta__btns">
            <button className="btn btn-gold" onClick={() => go("app")}>
              <span>Launch the App →</span>
            </button>
            <button className="btn btn-ghost" onClick={() => go("tech")}>
              Review the Tech
            </button>
          </div>
        </div>
      </section>
    </div>
  );
}
